    13→[[maybe_unused]] ssize_t connectingCapacity(const std::list<ActiveClientPtr>& connecting_clients) {
    14→  ssize_t ret = 0;
    15→  for (const auto& client : connecting_clients) {
    16→    ret += client->currentUnusedCapacity();
    17→  }
    18→  return ret;
    19→}
