   166→void ConnPoolImplBase::attachStreamToClient(Envoy::ConnectionPool::ActiveClient& client,
   167→                                            AttachContext& context) {
   168→  ASSERT(client.readyForStream());
   169→
   170→  Upstream::ClusterTrafficStats& traffic_stats = *host_->cluster().trafficStats();
   171→  if (client.state() == Envoy::ConnectionPool::ActiveClient::State::ReadyForEarlyData) {
   172→    traffic_stats.upstream_rq_0rtt_.inc();
   173→  }
   174→
   175→  if (enforceMaxRequests() && !host_->cluster().resourceManager(priority_).requests().canCreate()) {
   176→    ENVOY_LOG(debug, "max streams overflow");
   177→    onPoolFailure(client.real_host_description_, absl::string_view(),
   178→                  ConnectionPool::PoolFailureReason::Overflow, context);
   179→    traffic_stats.upstream_rq_pending_overflow_.inc();
   180→    return;
   181→  }
   182→  ENVOY_CONN_LOG(debug, "creating stream", client);
   183→
   184→  // Latch capacity before updating remaining streams.
   185→  uint64_t capacity = client.currentUnusedCapacity();
   186→  client.remaining_streams_--;
   187→  if (client.remaining_streams_ == 0) {
   188→    ENVOY_CONN_LOG(debug, "maximum streams per connection, start draining", client);
   189→    traffic_stats.upstream_cx_max_requests_.inc();
   190→    transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Draining);
   191→  } else if (capacity == 1) {
   192→    // As soon as the new stream is created, the client will be maxed out.
   193→    transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Busy);
   194→  }
   195→
   196→  // Decrement the capacity, as there's one less stream available for serving.
   197→  // For HTTP/3, the capacity is updated in newStreamEncoder.
   198→  if (trackStreamCapacity()) {
   199→    decrConnectingAndConnectedStreamCapacity(1, client);
   200→  }
   201→  // Track the new active stream.
   202→  state_.incrActiveStreams(1);
   203→  num_active_streams_++;
   204→  host_->stats().rq_total_.inc();
   205→  host_->stats().rq_active_.inc();
   206→  traffic_stats.upstream_rq_total_.inc();
   207→  traffic_stats.upstream_rq_active_.inc();
   208→  host_->cluster().resourceManager(priority_).requests().inc();
   209→
   210→  onPoolReady(client, context);
   211→}
