    28→std::unique_ptr<RetryStateImpl>
    29→RetryStateImpl::create(const RetryPolicy& route_policy, Http::RequestHeaderMap& request_headers,
    30→                       const Upstream::ClusterInfo& cluster, const VirtualCluster* vcluster,
    31→                       RouteStatsContextOptRef route_stats_context,
    32→                       Server::Configuration::CommonFactoryContext& context,
    33→                       Event::Dispatcher& dispatcher, Upstream::ResourcePriority priority) {
    34→  std::unique_ptr<RetryStateImpl> ret;
    35→
    36→  // We short circuit here and do not bother with an allocation if there is no chance we will retry.
    37→  // But for HTTP/3 0-RTT safe requests, which can be rejected because they are sent too early(425
    38→  // response code), we want to give them a chance to retry as normal requests even though the retry
    39→  // policy doesn't specify it. So always allocate retry state object.
    40→  if (request_headers.EnvoyRetryOn() || request_headers.EnvoyRetryGrpcOn() ||
    41→      route_policy.retryOn()) {
    42→    ret.reset(new RetryStateImpl(route_policy, request_headers, cluster, vcluster,
    43→                                 route_stats_context, context, dispatcher, priority, false));
    44→  } else if ((cluster.features() & Upstream::ClusterInfo::Features::HTTP3) &&
    45→             Http::Utility::isSafeRequest(request_headers)) {
    46→    ret.reset(new RetryStateImpl(route_policy, request_headers, cluster, vcluster,
    47→                                 route_stats_context, context, dispatcher, priority, true));
    48→  }
    49→
    50→  // Consume all retry related headers to avoid them being propagated to the upstream
    51→  request_headers.removeEnvoyRetryOn();
    52→  request_headers.removeEnvoyRetryGrpcOn();
    53→  request_headers.removeEnvoyMaxRetries();
    54→  request_headers.removeEnvoyHedgeOnPerTryTimeout();
    55→  request_headers.removeEnvoyRetriableHeaderNames();
    56→  request_headers.removeEnvoyRetriableStatusCodes();
    57→  request_headers.removeEnvoyUpstreamRequestPerTryTimeoutMs();
