    62→RetryStateImpl::RetryStateImpl(const RetryPolicy& route_policy,
    63→                               Http::RequestHeaderMap& request_headers,
    64→                               const Upstream::ClusterInfo& cluster, const VirtualCluster* vcluster,
    65→                               RouteStatsContextOptRef route_stats_context,
    66→                               Server::Configuration::CommonFactoryContext& context,
    67→                               Event::Dispatcher& dispatcher, Upstream::ResourcePriority priority,
    68→                               bool auto_configured_for_http3)
    69→    : cluster_(cluster), vcluster_(vcluster), route_stats_context_(route_stats_context),
    70→      runtime_(context.runtime()), random_(context.api().randomGenerator()),
    71→      dispatcher_(dispatcher), time_source_(context.timeSource()),
    72→      retry_host_predicates_(route_policy.retryHostPredicates()),
    73→      retry_priority_(route_policy.retryPriority()),
    74→      retriable_status_codes_(route_policy.retriableStatusCodes()),
    75→      retriable_headers_(route_policy.retriableHeaders()),
    76→      reset_headers_(route_policy.resetHeaders()),
    77→      reset_max_interval_(route_policy.resetMaxInterval()), retry_on_(route_policy.retryOn()),
    78→      retries_remaining_(route_policy.numRetries()), priority_(priority),
    79→      auto_configured_for_http3_(auto_configured_for_http3) {
    80→  if ((cluster.features() & Upstream::ClusterInfo::Features::HTTP3) &&
    81→      Http::Utility::isSafeRequest(request_headers)) {
    82→    // Because 0-RTT requests could be rejected because they are sent too early, and such requests
    83→    // should always be retried, setup retry policy for 425 response code for all potential 0-RTT
    84→    // requests even though the retry policy isn't configured to do so. Since 0-RTT safe requests
    85→    // traditionally shouldn't have body, automatically retrying them will not cause extra
    86→    // buffering. This will also enable retry if they are reset during connect.
    87→    retry_on_ |= RetryPolicy::RETRY_ON_RETRIABLE_STATUS_CODES;
    88→    retriable_status_codes_.push_back(static_cast<uint32_t>(Http::Code::TooEarly));
    89→  }
    90→  std::chrono::milliseconds base_interval(
    91→      runtime_.snapshot().getInteger("upstream.base_retry_backoff_ms", 25));
    92→  if (route_policy.baseInterval()) {
    93→    base_interval = *route_policy.baseInterval();
    94→  }
    95→
    96→  // By default, cap the max interval to 10 times the base interval to ensure reasonable back-off
    97→  // intervals.
    98→  std::chrono::milliseconds max_interval = base_interval * 10;
    99→  if (route_policy.maxInterval()) {
   100→    max_interval = *route_policy.maxInterval();
   101→  }
   102→
   103→  backoff_strategy_ = std::make_unique<JitteredExponentialBackOffStrategy>(
   104→      base_interval.count(), max_interval.count(), random_);
   105→  host_selection_max_attempts_ = route_policy.hostSelectionMaxAttempts();
   106→
   107→  // Merge in the headers.
   108→  if (request_headers.EnvoyRetryOn()) {
   109→    retry_on_ |= parseRetryOn(request_headers.getEnvoyRetryOnValue()).first;
   110→  }
   111→  if (request_headers.EnvoyRetryGrpcOn()) {
   112→    retry_on_ |= parseRetryGrpcOn(request_headers.getEnvoyRetryGrpcOnValue()).first;
   113→  }
   114→
   115→  const auto& retriable_request_headers = route_policy.retriableRequestHeaders();
   116→  if (!retriable_request_headers.empty()) {
   117→    // If this route limits retries by request headers, make sure there is a match.
   118→    bool request_header_match = false;
   119→    for (const auto& retriable_header : retriable_request_headers) {
   120→      if (retriable_header->matchesHeaders(request_headers)) {
   121→        request_header_match = true;
