   258→void RetryStateImpl::resetRetry() {
   259→  if (backoff_callback_ != nullptr) {
   260→    cluster_.resourceManager(priority_).retries().dec();
   261→    backoff_callback_ = nullptr;
   262→  }
   263→  if (next_loop_callback_ != nullptr) {
   264→    cluster_.resourceManager(priority_).retries().dec();
   265→    next_loop_callback_ = nullptr;
   266→  }
