   338→RetryStatus RetryStateImpl::shouldRetryHeaders(const Http::ResponseHeaderMap& response_headers,
   339→                                               const Http::RequestHeaderMap& original_request,
   340→                                               DoRetryHeaderCallback callback) {
   341→  // This may be overridden in wouldRetryFromHeaders().
   342→  bool disable_early_data = false;
   343→  const RetryDecision retry_decision =
   344→      wouldRetryFromHeaders(response_headers, original_request, disable_early_data);
   345→
   346→  // Yes, we will retry based on the headers - try to parse a rate limited reset interval from the
   347→  // response.
   348→  if (retry_decision == RetryDecision::RetryWithBackoff && !reset_headers_.empty()) {
   349→    const auto backoff_interval = parseResetInterval(response_headers);
   350→    if (backoff_interval.has_value() && (backoff_interval.value().count() > 1L)) {
   351→      ratelimited_backoff_strategy_ = std::make_unique<JitteredLowerBoundBackOffStrategy>(
   352→          backoff_interval.value().count(), random_);
   353→    }
   354→  }
   355→
   356→  return shouldRetry(retry_decision,
   357→                     [disable_early_data, callback]() { callback(disable_early_data); });
   358→}
